DO
BEGIN
  DECLARE table_exists INTEGER;

  SELECT COUNT(*)
    INTO table_exists
    FROM SYS.TABLES
   WHERE SCHEMA_NAME = 'ITIL_EXAM'
     AND TABLE_NAME = 'ADMIN_AUDIT_LOG';

  IF :table_exists = 0 THEN
    EXECUTE IMMEDIATE '
      CREATE TABLE "ITIL_EXAM"."ADMIN_AUDIT_LOG" (
        "AUDIT_ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
        "ACTION" NVARCHAR(80) NOT NULL,
        "TARGET_CODE" NVARCHAR(20) NULL,
        "DETAILS_JSON" NCLOB NULL,
        "ACTOR" NVARCHAR(120) NOT NULL,
        "CLIENT_IP" NVARCHAR(120) NULL,
        "CREATED_AT" TIMESTAMP DEFAULT CURRENT_UTCTIMESTAMP NOT NULL
      )
    ';
  END IF;
END;
